import React, { useState } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Type, CheckSquare, Square, ListChecks, X as XIcon } from 'lucide-react';
import { generateSpeech } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  settings: AppSettings;
}

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'word' | 'sentence'>('word');

  // Selection State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const audio = new Audio("data:audio/wav;base64," + b64);
             audio.onended = () => setPlayingId(null);
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error(e);
          setPlayingId(null);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Square Aspect Ratio
      canvas.width = 800;
      canvas.height = 800;

      // --- Background: Cyberpunk Dark ---
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Grid Pattern
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) {
        ctx.beginPath();
        ctx.moveTo(i, 0);
        ctx.lineTo(i, canvas.height);
        ctx.stroke();
      }
      for(let i=0; i < canvas.height; i+=40) {
        ctx.beginPath();
        ctx.moveTo(0, i);
        ctx.lineTo(canvas.width, i);
        ctx.stroke();
      }

      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);

      // Corner Accents (Cyberpunk style)
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize); // TL
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize); // TR
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize); // BL
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize); // BR

      let y = margin + 40;

      // --- Header: Metadata ---
      // Date
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;

      // Source Info
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }

      if (item.sourceChapter) {
          ctx.fillStyle = '#22d3ee';
          ctx.font = '16px "Courier New", monospace';
          ctx.fillText(`CHAPTER: ${item.sourceChapter.substring(0, 35)}`, margin, y);
          y += 25;
      }

      if (item.contextSource) {
          ctx.fillStyle = '#f59e0b'; // Amber
          ctx.font = '16px "Courier New", monospace';
          ctx.fillText(`ORIGIN: [${item.contextSource.toUpperCase()}]`, margin, y);
          y += 25;
      }

      // Divider
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(margin, y);
      ctx.lineTo(canvas.width - margin, y);
      ctx.stroke();
      y += 40;

      // --- Main Text Content (Auto-Scaling) ---
      // Base font size
      let fontSize = 32;
      // Use selected font setting or fallback
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;

      const words = item.text.split(' ');
      let lines = [];
      let line = '';

      // Function to calculate lines
      const calculateLines = () => {
         lines = [];
         line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line);
              line = words[n] + ' ';
            } else {
              line = testLine;
            }
         }
         lines.push(line);
      };

      calculateLines();

      // Auto-scale down if text takes too much vertical space
      const maxHeight = 350; // Adjusted for square layout + extra metadata

      // Loop to reduce font size if too tall
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2;
          ctx.font = `${fontSize}px ${mainFont}`;
          calculateLines();
      }

      // Draw Quote
      ctx.fillStyle = '#334155';
      ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);

      ctx.fillStyle = '#e2e8f0'; 
      ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;

      for (let i = 0; i < lines.length; i++) {
         ctx.fillText(lines[i], margin, y);
         y += lineHeight;
      }

      y += 30;

      // --- Definition Section ---
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; // Cyan
          ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y);
          y += 20;

          ctx.fillStyle = '#94a3b8';
          ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y);
               defLine = defWords[n] + ' ';
               y += 18;
            } else {
               defLine = testLine;
            }
         }
         ctx.fillText(defLine, margin, y);
         y += 35;
      }

      // --- Comments Section ---
      if (item.comment) {
          ctx.fillStyle = '#fb7185'; // Rose
          ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y);
          y += 20;

          ctx.fillStyle = '#fecdd3';
          ctx.font = '16px "Courier New", monospace';
          const cmtWords = item.comment.split(' ');
          let cmtLine = '';
          for(let n = 0; n < cmtWords.length; n++) {
            const testLine = cmtLine + cmtWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(cmtLine, margin, y);
               cmtLine = cmtWords[n] + ' ';
               y += 20;
            } else {
               cmtLine = testLine;
            }
         }
         ctx.fillText(cmtLine, margin, y);
      }

      // Footer
      ctx.fillStyle = '#1f2937';
      ctx.font = '10px "Courier New", monospace';
