  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [isVoiceDropdownOpen, setIsVoiceDropdownOpen] = useState(false);
  const [autoScroll, setAutoScroll] = useState(true);
  const [activeSentenceIndex, setActiveSentenceIndex] = useState<number>(-1);

  // Global Search State
  const [searchQuery, setSearchQuery] = useState("");
  const [searchMatches, setSearchMatches] = useState<GlobalMatch[]>([]);
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [bookSentences, setBookSentences] = useState<string[][]>([]);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const abortGenerationRef = useRef<boolean>(false);
  const isProgrammaticScroll = useRef(false);
  const activeMatchRef = useRef<HTMLSpanElement | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Track if we should regenerate on voice change
  const wasPlayingRef = useRef(false);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsVoiceDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const resetAudioState = () => {
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
  };

  const loadContent = async () => {
    setIsLoadingText(true);
    setError(null);
    setPages([]);
    setCurrentPage(0);
    setOriginalFullText(null);
    resetAudioState();

    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      setOriginalFullText(cleanText);
      const paginated = paginateText(cleanText, PAGE_TARGET_SIZE);
      setPages(paginated);
    } catch (err: any) {
      console.error("Text extraction failed", err);
      // Enhanced error handling to extract useful message from JSON errors
      let msg = err.message || "Failed to extract chapter text.";

      // Attempt to extract message from nested error object if available
      if (err.error && err.error.message) {
          msg = err.error.message;
      }

      const lowerMsg = msg.toLowerCase();
      if (lowerMsg.includes("quota") || lowerMsg.includes("429") || lowerMsg.includes("resource_exhausted")) {
          msg = "API Quota Exceeded. The system is paused to allow cooling down. Please try again in a minute.";
      }

      setError(msg);
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => {
    let mounted = true;
    loadContent();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  useEffect(() => {
    if (pages.length === 0) return;
    const processedPages = pages.map(pageText => {
        const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
        let pageSentences: string[] = [];
        rawParagraphs.forEach(pText => {
            const sents = splitIntoSentences(pText)
                .map(s => s.trim())
                .filter(s => s.length > 1 || (s.length === 1 && /[a-zA-Z0-9]/.test(s)));
            pageSentences = [...pageSentences, ...sents];
        });
        return pageSentences;
    });
    setBookSentences(processedPages);
  }, [pages]);

  useEffect(() => {
    if (!searchQuery.trim() || bookSentences.length === 0) {
        setSearchMatches([]);
        setCurrentMatchIdx(0);
        return;
    }
    const matches: GlobalMatch[] = [];
    const query = searchQuery.toLowerCase();
    bookSentences.forEach((sentences, pageIndex) => {
        let globalSentIdxCounter = 0; 
        const pageText = pages[pageIndex];
        const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
        rawParagraphs.forEach(pText => {
            const sents = splitIntoSentences(pText)
                .map(s => s.trim())
                .filter(s => s.length > 1 || (s.length === 1 && /[a-zA-Z0-9]/.test(s)));
            sents.forEach(s => {
                const sLower = s.toLowerCase();
                if (sLower.includes(query)) {
                    const parts = sLower.split(query);
                    for(let i=0; i < parts.length - 1; i++) {
                        matches.push({
                            pageIndex,
                            sentenceGlobalIndex: globalSentIdxCounter,
                            matchIndexInSentence: i,
                            text: searchQuery
                        });
                    }
                }
                globalSentIdxCounter++;
            });
        });
    });
    setSearchMatches(matches);
    setCurrentMatchIdx(0);
  }, [searchQuery, bookSentences, pages]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText)
            .map(s => s.trim())
            .filter(s => s.length > 1 || (s.length === 1 && /[a-zA-Z0-9]/.test(s)));
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({
                 pIndex,
                 sIndex,
                 globalIndex: globalIdx,
                 text: s
             });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (viewMode === 'split' && pages[currentPage]) {
        setIsTranslating(true);
        try {
          const translatedText = await translateText(pages[currentPage], settings.targetLanguage);
          const cleanTranslated = rearrangeAndCleanText(translatedText);
          const rawTransParagraphs = cleanTranslated.split(/\n\s*\n/).filter(p => p.trim().length > 0);
          const isChineseTarget = settings.targetLanguage.includes("Chinese");
          setParagraphData(prev => {
              return prev.map((p, idx) => {
                  const tText = rawTransParagraphs[idx] || "";
                  return { ...p, translated: splitIntoSentences(tText, isChineseTarget) };
              });
          });
        } catch(e) { console.error("Translation error", e); } finally { setIsTranslating(false); }
      }
    };
    loadTranslation();
  }, [currentPage, viewMode, settings.targetLanguage, pages]);

  useEffect(() => {
    if (audioRef.current) audioRef.current.playbackRate = playbackRate;
  }, [playbackRate]);

  useEffect(() => {
    let animationFrameId: number;
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const t = audioRef.current.currentTime;
        const d = audioRef.current.duration;
        setCurrentTime(t);
        setDuration(d || 0);
        setPlaybackProgress((t / (d || 1)) * 100);
        const activeIdx = timings.findIndex(chunk => 
            !chunk.isWhitespace && t >= chunk.start && t < chunk.end
        );
        if (activeIdx !== -1) {
            setActiveSentenceIndex(prev => prev !== activeIdx ? activeIdx : prev);
        }
        if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    return () => { if (animationFrameId) cancelAnimationFrame(animationFrameId); };
  }, [isPlaying, timings]);

  useEffect(() => {
    if (!autoScroll) return;
    if (activeSentenceIndex !== -1 && flatSentenceMap[activeSentenceIndex]) {
        const sentenceEl = document.getElementById(`original-sent-${activeSentenceIndex}`);
        if (sentenceEl) {
             isProgrammaticScroll.current = true;
             sentenceEl.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' });
             const scrollTimeout = setTimeout(() => { isProgrammaticScroll.current = false; }, 800);
            return () => clearTimeout(scrollTimeout);
        }
    }
  }, [activeSentenceIndex, autoScroll, flatSentenceMap]); 

  useEffect(() => {
      if (searchMatches.length > 0 && searchMatches[currentMatchIdx]) {
          const match = searchMatches[currentMatchIdx];
          if (match.pageIndex !== currentPage) {
              setCurrentPage(match.pageIndex);
          } else {
             if (activeMatchRef.current) {
                 activeMatchRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
             }
          }
      }
  }, [currentMatchIdx, searchMatches, currentPage]);

  useEffect(() => {
      if (activeMatchRef.current) {
         activeMatchRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
  }, [currentPage]);

  useEffect(() => {
    if (audioSrc && !isGenerating && audioRef.current) {
        audioRef.current.load();
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
            playPromise
                .then(() => setIsPlaying(true))
                .catch(e => console.warn("Autoplay blocked by browser policy", e));
        }
    }
  }, [audioSrc, isGenerating]);

  // Handle voice change and regeneration
  useEffect(() => {
      if (wasPlayingRef.current && !audioSrc && !isGenerating) {
          generatePageAudio();
          wasPlayingRef.current = false;
      }
  }, [audioSrc, isGenerating, selectedVoice]);

  const handleContainerScroll = () => { if (isProgrammaticScroll.current) return; };

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setGenerationProgress("INIT_VOICE_CORE...");
    try {
      const sentences = flatSentenceMap.map(m => m.text);
      let completedCount = 0;
      const audioResults = await processQueue<string, string | null>(
        sentences, CONCURRENCY_LIMIT, 
        async (sentence, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${completedCount + 1}_OF_${sentences.length}`);
           const b64 = await generateSpeech(sentence, selectedVoice);
           completedCount++;
           return b64;
        },
        () => abortGenerationRef.current
      );
      if (abortGenerationRef.current) { setIsGenerating(false); return; }
      setGenerationProgress("ASSEMBLING_STREAM...");
      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentByteOffset = 0;
      const BYTES_PER_SEC = 48000; 
      for (let i = 0; i < sentences.length; i++) {
        const b64 = audioResults[i];
        if (!b64) {
          newTimings.push({ text: sentences[i], start: currentByteOffset / BYTES_PER_SEC, end: currentByteOffset / BYTES_PER_SEC, isWhitespace: true });
          continue;
        }
        const binaryString = atob(b64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let k = 0; k < len; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);
        const durationSec = len / BYTES_PER_SEC;
        const startSec = currentByteOffset / BYTES_PER_SEC;
        newTimings.push({ text: sentences[i], start: startSec, end: startSec + durationSec, isWhitespace: false });
        currentByteOffset += len;
      }
      if (audioBuffers.length === 0) throw new Error("AUDIO_GEN_FAILURE");
      const mergedBuffer = new Uint8Array(currentByteOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }
      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeString = (view: DataView, offset: number, string: string) => { 
          for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i)); 
      };
      writeString(view, 0, 'RIFF'); 
      view.setUint32(4, 36 + currentByteOffset, true); 
      writeString(view, 8, 'WAVE'); 
      writeString(view, 12, 'fmt '); 
      view.setUint32(16, 16, true); 
      view.setUint16(20, 1, true); 
      view.setUint16(22, 1, true); 
      view.setUint32(24, 24000, true); 
      view.setUint32(28, 48000, true); 
      view.setUint16(32, 2, true); 
      view.setUint16(34, 16, true); 
      writeString(view, 36, 'data'); 
      view.setUint32(40, currentByteOffset, true);
      const blob = new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' });
      if (!abortGenerationRef.current) { 
          setTimings(newTimings); 
          const url = URL.createObjectURL(blob);
          setAudioSrc(url); 
      }
    } catch (e: any) {
      console.error("Audio generation failed:", e);
      if (!abortGenerationRef.current) { setGenerationProgress("ERR: " + (e.message || "UNKNOWN")); }
    } finally {
      if (!abortGenerationRef.current) setIsGenerating(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (audioRef.current && duration) {
       const newTime = (val / 100) * duration;
       audioRef.current.currentTime = newTime;
       setPlaybackProgress(val);
       setCurrentTime(newTime);
       const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && newTime >= chunk.start && newTime < chunk.end);
       if (activeIdx !== -1) setActiveSentenceIndex(activeIdx);
    }
  };

  const togglePlay = () => {
    if (!audioSrc) { generatePageAudio(); return; }
    if (audioRef.current) { isPlaying ? audioRef.current.pause() : audioRef.current.play(); }
  };

  // New function to skip audio
  const skipAudio = (seconds: number) => {
    if (audioRef.current) {
        const newTime = audioRef.current.currentTime + seconds;
        audioRef.current.currentTime = newTime;
        setCurrentTime(newTime);
        const activeIdx = timings.findIndex(chunk => 
            !chunk.isWhitespace && newTime >= chunk.start && newTime < chunk.end
        );
        if (activeIdx !== -1) {
            setActiveSentenceIndex(activeIdx);
        }
    }
  };

  const changePage = (delta: number) => {
    const newPage = currentPage + delta;
    if (newPage >= 0 && newPage < pages.length) setCurrentPage(newPage);
  };

  const highlightSearch = (text: string, sentenceGlobalIndex: number) => {
      if (!searchQuery.trim()) return text;
      const regex = new RegExp(`(${escapeRegExp(searchQuery)})`, 'gi');
      const parts = text.split(regex);
      if (parts.length === 1) return text;
      let localMatchCounter = 0;
      return parts.map((part, i) => {
        if (part.toLowerCase() === searchQuery.toLowerCase()) {
            const isActiveMatch = searchMatches[currentMatchIdx] && 
                                  searchMatches[currentMatchIdx].pageIndex === currentPage &&
                                  searchMatches[currentMatchIdx].sentenceGlobalIndex === sentenceGlobalIndex &&
                                  searchMatches[currentMatchIdx].matchIndexInSentence === localMatchCounter;
            const element = (
                <span 
                    key={i} 
                    ref={isActiveMatch ? activeMatchRef : null}
                    className={`rounded-sm px-0.5 ${isActiveMatch ? 'bg-[#ff003c] text-white animate-pulse shadow-[0_0_10px_#ff003c]' : 'bg-[#ff003c]/30 text-white'}`}
                >
                    {part}
                </span>
            );
            localMatchCounter++;
            return element;
        }
        return part;
      });
  };

  const nextMatch = () => {
      if (searchMatches.length === 0) return;
      setCurrentMatchIdx(prev => (prev + 1) % searchMatches.length);
  };

  const prevMatch = () => {
      if (searchMatches.length === 0) return;
      setCurrentMatchIdx(prev => (prev - 1 + searchMatches.length) % searchMatches.length);
  };

  if (isLoadingText) return <Loader text="DECODING_TEXT_BLOCK..." className="h-full" />;

  if (error) {
    return (
      <div className="h-full flex flex-col items-center justify-center p-8 text-center animate-fade-in font-tech">
        <div className="w-16 h-16 bg-[#ff003c]/10 rounded-full flex items-center justify-center mb-6 border border-[#ff003c]/30">
          <AlertTriangle className="w-8 h-8 text-[#ff003c]" />
        </div>
        <h3 className="text-xl font-bold text-white mb-2 uppercase tracking-widest">CRITICAL_FAILURE</h3>
        <p className="text-zinc-500 max-w-md mb-8 font-mono text-sm">{error}</p>
        <button onClick={loadContent} className="px-6 py-2 bg-zinc-900 hover:bg-zinc-800 text-white rounded-sm border border-zinc-700 hover:border-[#00f3ff] transition-all flex items-center gap-2 font-mono uppercase text-xs font-bold">
          <RotateCcw size={14} /> REINITIALIZE
        </button>
      </div>
    );
  }

  const canPrev = currentPage > 0;
  const canNext = currentPage < pages.length - 1;
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const currentVoiceLabel = VOICES.find(v => v.name === selectedVoice)?.label || selectedVoice;
  const currentVoiceName = VOICES.find(v => v.name === selectedVoice)?.name || selectedVoice;

  return (
    <div className="h-full flex flex-col gap-4 animate-fade-in relative font-sans text-zinc-100" style={fontStyle}>
      <audio ref={audioRef} src={audioSrc || undefined} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} onEnded={() => setIsPlaying(false)} className="hidden" />

      {/* Cyberpunk Header Controls */}
      <div className="flex items-center justify-between bg-black/80 border border-zinc-800 p-3 rounded-sm backdrop-blur-md shrink-0 flex-wrap gap-4 shadow-[0_0_20px_rgba(0,0,0,0.5)]">
         <div className="flex items-center gap-4">
            <button onClick={() => changePage(-1)} disabled={!canPrev} className="p-2 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all">
              <ChevronLeft size={16} />
            </button>
            <div className="text-center min-w-[80px]">
               <h3 className="text-xs font-bold text-[#00f3ff] uppercase tracking-widest font-tech">PG.{String(currentPage + 1).padStart(2,'0')}</h3>
               <span className="text-[9px] text-zinc-600 font-mono">MAX.{String(pages.length).padStart(2,'0')}</span>
            </div>
            <button onClick={() => changePage(1)} disabled={!canNext} className="p-2 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all">
              <ChevronRight size={16} />
            </button>
         </div>

         <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-900 px-3 py-1.5 rounded-sm mx-2 flex-1 max-w-sm focus-within:border-[#00f3ff]/50 transition-colors">
             <Search size={14} className="text-zinc-600" />
             <input 
                type="text" 
                placeholder="GLOBAL_SCAN..." 
                value={searchQuery} 
                onChange={(e) => setSearchQuery(e.target.value)} 
                onKeyDown={(e) => e.key === 'Enter' && nextMatch()}
                className="bg-transparent text-xs text-[#00f3ff] focus:outline-none w-full font-mono placeholder:text-zinc-700 uppercase" 
             />
             {searchMatches.length > 0 ? (
                 <div className="flex items-center gap-2 text-[10px] font-mono text-zinc-400 bg-zinc-900 px-1 rounded">
                     <span>{currentMatchIdx + 1}/{searchMatches.length}</span>
                     <div className="flex flex-col">
                        <button onClick={prevMatch} className="hover:text-white"><ChevronUp size={8} /></button>
                        <button onClick={nextMatch} className="hover:text-white"><ChevronDown size={8} /></button>
                     </div>
                 </div>
             ) : (
                <span className="text-[9px] text-zinc-700 font-mono">0/0</span>
             )}
         </div>

         <div className="flex items-center gap-2">
             <button onClick={() => setViewMode(viewMode === 'split' ? 'single' : 'split')} className={`flex items-center gap-2 px-3 py-1.5 rounded-sm text-[9px] font-bold font-tech transition-all border ${viewMode === 'split' ? 'bg-[#00f3ff]/10 border-[#00f3ff] text-[#00f3ff]' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                {viewMode === 'split' ? <SplitSquareHorizontal size={14} /> : <Columns size={14} />}
                {viewMode === 'split' ? "SPLIT_MODE" : "SINGLE_MODE"}
             </button>

             <button onClick={() => setAutoScroll(!autoScroll)} className={`flex items-center gap-2 px-3 py-1.5 rounded-sm text-[9px] font-bold font-tech transition-all border ${autoScroll ? 'bg-emerald-900/20 border-emerald-500 text-emerald-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                {autoScroll ? <Eye size={14} /> : <EyeOff size={14} />}
                AUTO_TRACK
             </button>

             {/* Custom Voice Dropdown */}
             <div className="relative" ref={dropdownRef}>
                <button 
                  onClick={() => setIsVoiceDropdownOpen(!isVoiceDropdownOpen)}
                  className="flex items-center gap-2 ml-2 bg-zinc-950 border border-zinc-800 px-3 py-1.5 rounded-sm hover:border-zinc-700 transition-colors"
                >
                   <Mic2 size={14} className="text-[#ff003c]" />
                   <span className="text-[10px] text-[#00f3ff] font-mono uppercase min-w-[60px] text-left">
                      {currentVoiceName} 
                   </span>
                   <ChevronDown size={10} className="text-zinc-600" />
                </button>

                {isVoiceDropdownOpen && (
                   <div className="absolute top-full right-0 mt-1 bg-[#050505] border border-zinc-800 rounded-sm shadow-xl z-50 min-w-[140px] overflow-hidden">
                      {VOICES.map(v => (
                         <button
                            key={v.name}
                            onClick={() => {
                                if (isPlaying) {
                                    wasPlayingRef.current = true;
                                    if (audioRef.current) audioRef.current.pause();
                                }
                                setSelectedVoice(v.name); 
                                resetAudioState();
                                setIsVoiceDropdownOpen(false);
                            }}
                            className={`w-full text-left px-3 py-2 text-[10px] font-mono uppercase hover:bg-zinc-900 flex items-center justify-between ${selectedVoice === v.name ? 'text-[#00f3ff] bg-zinc-900/50' : 'text-zinc-400'}`}
                         >
                            <span>{v.label}</span>
                            {selectedVoice === v.name && <Check size={10} />}
                         </button>
                      ))}
                   </div>
                )}
             </div>
         </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden rounded-sm border border-zinc-800 bg-[#050505] relative flex flex-col hud-border">
         <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-[#00f3ff]/30 to-transparent z-10"></div>

         <div className={`flex shrink-0 border-b border-zinc-800 bg-[#0a0a0c]/90 backdrop-blur-md z-10 w-full`}>
            <div className={`p-4 ${viewMode === 'split' ? 'w-1/2 border-r border-zinc-800' : 'w-full max-w-3xl mx-auto'}`}>
                <h2 className="text-[10px] font-bold font-tech uppercase tracking-widest text-[#00f3ff] flex items-center justify-between">
                    Input_Stream.v1
                    <span className="text-[8px] text-zinc-500 border border-zinc-800 px-1 rounded-sm">RAW_DATA</span>
                </h2>
            </div>
            {viewMode === 'split' && (
                <div className="w-1/2 p-4">
                     <h2 className="text-[10px] font-bold font-tech uppercase tracking-widest text-[#ff003c] flex items-center justify-between">
                        Decoded_Layer.v2
                        <div className="flex items-center gap-2">
                            {isTranslating && <LoaderIcon size={10} className="animate-spin text-[#ff003c]" />}
                            <span className="text-[8px] text-zinc-500 border border-zinc-800 px-1 rounded-sm">{settings.targetLanguage.toUpperCase()}</span>
                        </div>
                    </h2>
                </div>
            )}
         </div>

         <div className="flex-1 overflow-y-auto scroll-smooth custom-scrollbar relative p-4 pb-48" onScroll={handleContainerScroll}>
             {paragraphData.length === 0 ? (
                 <div className="flex flex-col items-center justify-center h-full text-zinc-600 font-mono text-xs gap-4">
                     <Terminal size={32} className="opacity-20" />
                     <span>AWAITING_NEURAL_BUFFER...</span>
                 </div>
             ) : (
                <div className={`flex flex-col gap-8 ${viewMode === 'split' ? '' : 'items-center'}`}>
                    {paragraphData.map((para, pIdx) => {
                        const paragraphMap = flatSentenceMap.filter(m => m.pIndex === pIdx);
                        return (
                            <div key={pIdx} className={`w-full ${viewMode === 'split' ? 'flex' : 'max-w-3xl flex flex-col'} p-2`}>
                                <div data-source="Input_Stream" className={`${viewMode === 'split' ? 'w-1/2 pr-4 border-r border-zinc-800/50' : 'w-full'} ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-400 font-medium whitespace-pre-wrap`}>
                                    {para.original.map((sentence, sIdx) => {
                                        const mapping = paragraphMap.find(m => m.sIndex === sIdx);
                                        const globalIdx = mapping ? mapping.globalIndex : -1;
                                        // Highlight depends on autoScroll flag AND being active
                                        const isActive = autoScroll && globalIdx === activeSentenceIndex;
                                        const timing = timings[globalIdx]; 
                                        return (
                                            <span key={sIdx} id={`original-sent-${globalIdx}`} onClick={() => { if (audioRef.current && timing && !timing.isWhitespace) { audioRef.current.currentTime = timing.start; audioRef.current.play(); } }} className={`transition-all duration-300 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : 'hover:text-zinc-200 cursor-pointer'}`}>
                                                {highlightSearch(sentence, globalIdx)}{' '}
                                            </span>
                                        );
                                    })}
                                </div>
                                {viewMode === 'split' && (
                                    <div data-source="Decoded_Layer" className={`w-1/2 pl-4 ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-500 font-medium whitespace-pre-wrap`}>
                                        {isTranslating && para.translated.length === 0 ? (
                                            <span className="animate-pulse text-[10px] font-mono text-zinc-700">DECRYPTING...</span>
                                        ) : (
                                            para.translated.map((tSent, tIdx) => {
                                                let isTransActive = false;
                                                const isActivePara = paragraphMap.some(m => m.globalIndex === activeSentenceIndex);

                                                if (isActivePara && para.original.length > 0) {
                                                    const currentSentInPara = flatSentenceMap[activeSentenceIndex]?.sIndex ?? 0;

                                                    // Improved Synchronization Logic
                                                    if (para.original.length === para.translated.length) {
                                                        // Exact match: 1-to-1 mapping
                                                        isTransActive = tIdx === currentSentInPara;
                                                    } else {
                                                        // Fallback: Ratio mapping
                                                        const ratio = currentSentInPara / para.original.length;
                                                        const targetIdx = Math.floor(ratio * para.translated.length);
                                                        isTransActive = tIdx === targetIdx;
                                                    }
                                                }

                                                // Sync translation highlight with autoScroll toggle
                                                const finalIsTransActive = autoScroll && isTransActive;

                                                return (
                                                    <span key={tIdx} className={`transition-all duration-500 px-[2px] ${finalIsTransActive ? HIGHLIGHT_STYLES[settings.highlightColor] : ''}`}>
                                                        {tSent}{' '}
                                                    </span>
                                                );
                                            })
                                        )}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
             )}
         </div>
      </div>

      {/* Footer Controls */}
      <div className="bg-[#020202] border-t border-zinc-800 p-4 flex flex-col gap-4 z-20 absolute bottom-0 left-0 right-0 shadow-[0_-10px_30px_rgba(0,0,0,0.8)]">
         <div className="flex items-center gap-3 w-full font-mono text-[10px] text-[#00f3ff]">
            <span className="w-10 text-right">{formatTime(currentTime)}</span>
            <div className="flex-1 h-1 bg-zinc-900 relative group cursor-pointer border border-zinc-800">
               <input type="range" min="0" max="100" value={playbackProgress} onChange={handleSeek} disabled={!audioSrc} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
               <div className="h-full bg-[#00f3ff] relative" style={{ width: `${playbackProgress}%` }}>
                 <div className="absolute right-0 top-1/2 -translate-y-1/2 w-1.5 h-3 bg-white shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
               </div>
            </div>
            <span className="w-10">{formatTime(duration)}</span>
         </div>

         <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 font-mono text-[9px] text-zinc-600">
                <span className="uppercase tracking-widest border border-zinc-800 px-1">T_RATE</span>
                {[1, 1.25, 1.5, 2].map(r => (
                    <button key={r} onClick={() => setPlaybackRate(r)} className={`px-2 py-0.5 border transition-all ${playbackRate === r ? 'border-[#00f3ff] text-[#00f3ff] bg-[#00f3ff]/10' : 'border-zinc-800 hover:border-zinc-700 text-zinc-500'}`}>
                      {r}x
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-6">
               <button 
                 onClick={() => skipAudio(-5)}
                 disabled={!audioSrc}
                 className="p-3 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full"
                 title="Rewind 5s"
               >
                 <Rewind size={20} />
               </button>

               <button onClick={togglePlay} disabled={isGenerating} className={`w-12 h-12 flex items-center justify-center border transition-all active:scale-95 ${isGenerating ? 'bg-zinc-900 border-zinc-800 cursor-wait' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_15px_rgba(0,243,255,0.4)] hover:bg-white'}`}>
                 {isGenerating ? <LoaderIcon size={20} className="animate-spin text-[#00f3ff]" /> : isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-0.5" />}
               </button>

               <button 
                 onClick={() => skipAudio(5)}
                 disabled={!audioSrc}
                 className="p-3 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full"
                 title="Forward 5s"
               >
                 <FastForward size={20} />
               </button>
            </div>

            <div className="flex items-center gap-3 justify-end w-40">
                 {audioSrc ? (
                    <a 
                        href={audioSrc} 
                        download={`lumina-ch${chapter.id}-pg${currentPage + 1}.wav`} 
                        className="p-2 text-zinc-600 hover:text-[#ff003c] transition-colors border border-transparent hover:border-[#ff003c]/30 rounded-sm" 
                        title="Export Wav"
                    >
                        <Download size={18} />
                    </a>
                 ) : (
                    <button disabled className="p-2 text-zinc-800 cursor-not-allowed">
                        <Download size={18} />
                    </button>
                 )}
                <div className="truncate text-right font-mono text-[9px]">
                    {isGenerating ? <span className="text-[#00f3ff] animate-pulse">{generationProgress}</span> : !audioSrc ? <span className="text-zinc-700">SYS.IDLE</span> : <span className="text-emerald-500">SYS.READY</span>}
                </div>
            </div>
         </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, RefreshCw } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

// Alphabetical order with Chinese (Traditional) added
const LANGUAGES = [
  'Arabic',
  'Chinese (Simplified)',
  'Chinese (Traditional)',
  'Dutch',
  'English',
  'French',
  'German',
  'Hindi',
  'Indonesian',
  'Italian',
  'Japanese',
  'Korean',
  'Polish',
  'Portuguese',
  'Russian',
  'Spanish',
  'Swedish',
  'Thai',
  'Turkish',
  'Vietnamese'
];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);

  // Audio Context Refs for Visualizer
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaElementAudioSourceNode | null>(null);

  useEffect(() => {
    // Sync default language if settings change (optional, but good for UX)
    setSelectedLanguage(settings.targetLanguage);
  }, [settings.targetLanguage]);

  const writeString = (view: DataView, offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) {
      view.setUint8(offset + i, string.charCodeAt(i));
    }
  };

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);

    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 24000 * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);

    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    const blob = new Blob([buffer], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const cleanText = (text: string) => {
      return text.replace(/\*\*/g, '').trim();
  };

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }

    const lines = script.split('\n').filter(line => line.trim().length > 0);
    const totalChars = lines.reduce((acc, line) => acc + line.length, 0);

    let accumulatedChars = 0;
    const parsed: ScriptSegment[] = lines.map(line => {
      let speaker = 'Host';
      let text = line;

      if (line.includes(':')) {
        const parts = line.split(/:(.+)/);
        if (parts.length > 1) {
          speaker = cleanText(parts[0]);
          text = cleanText(parts[1]);
        }
      }

      const startPct = accumulatedChars / totalChars;
      accumulatedChars += line.length;
      const endPct = accumulatedChars / totalChars;

      return { speaker, text, startPct, endPct };
    });

    setSegments(parsed);
  }, [script]);

  const handleGenerate = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const hostConfig = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];
      // Use selectedLanguage state explicitly selected by user
      const { audio, script } = await generatePodcastAudio(fileContext, chapter, selectedTone, hostConfig, selectedLanguage);
      const wavUrl = pcmToWavBlobUrl(audio);
      setAudioSrc(wavUrl);
      setScript(script);
      setActiveIndex(-1);
    } catch (e: any) {
      setError(e.message || "Failed to generate podcast. Please try again.");
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRegenerate = () => {
    if (audioRef.current) {
      audioRef.current.pause();
    }
    setAudioSrc(null);
    setScript(null);
    setSegments([]);
    setActiveIndex(-1);
    setIsPlaying(false);
  };

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.style.display = 'none';
    a.href = url;
    a.download = `lumina-podcast-transcript-${chapter.id}.txt`;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }, 100);
  };

  const togglePlay = () => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.pause();
    } else {
      // Initialize Audio Context on first user interaction
      if (!audioContextRef.current) {
        initAudioVisualizer();
      }
      if (audioContextRef.current?.state === 'suspended') {
        audioContextRef.current.resume();
      }
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const skipForward = () => {
    if (audioRef.current) {
        audioRef.current.currentTime += 15;
    }
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;

    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128; // Lower FFT size for chunkier bars
      analyser.smoothingTimeConstant = 0.85;

      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);

      audioContextRef.current = ctx;
      analyserRef.current = analyser;
      sourceRef.current = source;
    } catch (e) {
      console.warn("Audio Context init failed (likely already connected or blocked)", e);
    }
  };

  const handleTimeUpdate = () => {
    if (!audioRef.current) return;

    const { currentTime, duration } = audioRef.current;
    if (!duration) return;

    const currentPct = currentTime / duration;
    // Find active segment, allowing for small timing buffers
    const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);

    if (index !== -1 && index !== activeIndex) {
      setActiveIndex(index);

      // Smooth scroll to element
      const el = segmentRefs.current[index];
      if (el) {
        el.scrollIntoView({
          behavior: 'smooth',
          block: 'nearest' // Changed from center to nearest for less jumpy behavior
        });
      }
    }
  };

  // Visualizer Animation Loop
  useEffect(() => {
    // Run loop as long as playing, regardless of host style
    if (!isPlaying || !canvasRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const draw = () => {
      // If we have an analyser, get real data, otherwise fallback to empty
      const bufferLength = analyserRef.current ? analyserRef.current.frequencyBinCount : 0;
      const dataArray = new Uint8Array(bufferLength);

      if (analyserRef.current) {
         analyserRef.current.getByteFrequencyData(dataArray);
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Use full width
      const barWidth = (canvas.width / bufferLength) * 2.5;
      let x = 0;

      // Draw mirrored spectrum from center
      const centerX = canvas.width / 2;

      // We only draw half the bars to mirror them
      const effectiveBars = bufferLength / 2;
      const step = canvas.width / 2 / effectiveBars;

      for (let i = 0; i < effectiveBars; i++) {
        // Use real data or simulated fallback if context not ready yet
        const value = analyserRef.current ? dataArray[i] : (isPlaying ? Math.random() * 50 : 0);

        const percent = value / 255;
        const height = percent * canvas.height * 0.9;

        // Gradient Colors: Cyan to Pink/Purple
        // Always uniform colors for smoother loop
        const r = 255 * percent;
        const g = 243 * (1 - percent);
        const b = 255;

        ctx.fillStyle = `rgb(${r},${g},${b})`;
        ctx.shadowBlur = 15;
        ctx.shadowColor = `rgba(${r},${g},${b},0.5)`;

        // Right side
        ctx.fillRect(centerX + (i * step), (canvas.height - height) / 2, step - 2, height);
        // Left side
        ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - height) / 2, step - 2, height);
      }

      animationRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying]); // Removed selectedTone/hosts dependency to ensure continuous operation

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  return (
    <div className="flex flex-col h-full gap-4 text-zinc-100 font-sans">
      {/* Cyberpunk Player Card */}
      <div className="flex-shrink-0 bg-[#0a0a0c] border border-cyan-900/40 rounded-lg p-6 relative overflow-hidden shadow-[0_0_20px_rgba(0,243,255,0.05)] min-h-[320px] flex flex-col justify-center">
        {/* Decorative Grid Background */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#1f2937_1px,transparent_1px),linear-gradient(to_bottom,#1f2937_1px,transparent_1px)] bg-[size:24px_24px] opacity-[0.05] pointer-events-none"></div>

        <div className="z-10 flex flex-col items-center justify-center w-full max-w-2xl mx-auto space-y-6">
          <div className="text-center space-y-2 animate-fade-in-up">
            <h2 className="text-2xl font-black text-white tracking-widest uppercase flex items-center justify-center gap-2 font-mono">
              <Mic2 size={24} className="text-[#00f3ff] drop-shadow-[0_0_8px_rgba(0,243,255,0.8)]"/>
              NEURAL_PODCAST
            </h2>
            <div className="flex items-center justify-center gap-3 text-xs font-mono">
               <span className="text-cyan-400">HOST: {cleanText(hosts.host1).toUpperCase()}</span>
               <span className="text-zinc-600">|</span>
               <span className="text-[#ff003c]">CO-HOST: {cleanText(hosts.host2).toUpperCase()}</span>
            </div>
            <p className="text-zinc-500 font-mono text-[10px] truncate max-w-md mx-auto">TOPIC: "{chapter.title}"</p>
          </div>

          {!audioSrc && !isLoading && (
            <div className="animate-fade-in flex flex-col items-center gap-4 w-full">
              <div className="flex items-center gap-2 w-full max-w-sm justify-center flex-wrap">
                 {/* Tone Selection */}
                 <div className="flex-1 min-w-[140px] flex items-center gap-2 bg-[#121214] px-3 py-2 rounded-sm border border-zinc-800 hover:border-cyan-500/50 transition-colors">
                    <Settings2 size={14} className="text-zinc-500" />
                    <select 
                      value={selectedTone}
                      onChange={(e) => setSelectedTone(e.target.value)}
                      className="bg-[#121214] text-xs text-[#00f3ff] outline-none cursor-pointer border-none font-bold uppercase w-full font-mono"
                    >
                      {TONES.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                 </div>

                 {/* Language Selection */}
                 <div className="flex-1 min-w-[140px] flex items-center gap-2 bg-[#121214] px-3 py-2 rounded-sm border border-zinc-800 hover:border-cyan-500/50 transition-colors">
                    <Globe size={14} className="text-zinc-500" />
                    <select
                      value={selectedLanguage}
                      onChange={(e) => setSelectedLanguage(e.target.value)}
                      className="bg-[#121214] text-xs text-[#00f3ff] outline-none cursor-pointer border-none font-bold uppercase w-full font-mono"
                    >
                      {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                    </select>
                 </div>
              </div>

              <button 
                onClick={handleGenerate}
                className="w-full max-w-xs px-8 py-3 bg-[#00f3ff] hover:bg-[#00c2cc] text-black rounded-[2px] font-bold uppercase tracking-wider transition-all shadow-[0_0_15px_rgba(0,243,255,0.4)] flex items-center justify-center gap-2 hover:scale-[1.02] active:scale-95 font-mono"
              >
                <Play size={18} fill="currentColor" />
                INITIATE_SEQUENCE
              </button>
            </div>
          )}

          {isLoading && <Loader text={`Synthesizing ${selectedTone} dialogue in ${selectedLanguage}...`} />}

          {audioSrc && (
            <div className="w-full space-y-6 animate-fade-in-up">
               {/* Visualizer Canvas */}
               <div className="h-32 bg-[#050505] rounded border border-zinc-800 w-full flex items-center justify-center overflow-hidden relative shadow-inner group">
                  <div className="absolute inset-0 bg-gradient-to-b from-transparent to-[#00f3ff]/5 pointer-events-none"></div>

                  {/* Grid overlay for visualizer */}
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                  <canvas ref={canvasRef} width={600} height={200} className="w-full h-full opacity-90"></canvas>

                  <div className="absolute top-2 right-2 flex gap-2">
                       {isPlaying && (
                         <div className="flex items-center gap-1 text-[#ff003c] animate-pulse">
                            <Radio size={12} />
                            <span className="text-[9px] font-bold font-mono">LIVE_FEED</span>
                         </div>
                       )}
                       <span className="text-[9px] font-mono text-zinc-600 border border-zinc-800 px-1">24kHz</span>
                  </div>
               </div>

               <audio 
                ref={audioRef} 
                src={audioSrc} 
                onTimeUpdate={handleTimeUpdate}
                onEnded={() => setIsPlaying(false)}
                onPlay={() => setIsPlaying(true)}
                onPause={() => setIsPlaying(false)}
                crossOrigin="anonymous" 
                className="hidden"
               />

               <div className="flex items-center justify-center gap-6">
                 <button 
                  onClick={() => {
                    if (audioRef.current) {
                      audioRef.current.currentTime = 0;
                      audioRef.current.play();
                      setIsPlaying(true);
                      setActiveIndex(-1);
                      if (scriptContainerRef.current) scriptContainerRef.current.scrollTop = 0;
                    }
                  }}
                  className="p-3 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full"
                  title="Reboot"
                 >
                   <RotateCcw size={20} />
                 </button>

                 <button 
                  onClick={togglePlay}
                  className={`w-14 h-14 rounded-full transition-all flex items-center justify-center border-2 ${
                     isPlaying 
                     ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' 
                     : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'
                  }`}
                 >
                   {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
                 </button>

                 <button
                  onClick={skipForward}
                  className="p-3 text-zinc-500 hover:text-[#00f3ff] transition-colors hover:bg-zinc-900 rounded-full"
                  title="Skip 15s"
                 >
                    <RotateCw size={20} />
                 </button>

                 <a 
                   href={audioSrc} 
                   download={`lumina-podcast-${chapter.id}.wav`}
                   className="p-3 text-zinc-500 hover:text-[#ff003c] transition-colors hover:bg-zinc-900 rounded-full"
                   title="Extract Audio"
                 >
                   <Download size={20} />
                 </a>

                 <button
                   onClick={handleRegenerate}
                   className="p-3 text-zinc-500 hover:text-[#00f3ff] transition-colors hover:bg-zinc-900 rounded-full"
                   title="Regenerate Podcast"
                 >
                   <RefreshCw size={20} />
                 </button>
               </div>
            </div>
          )}

          {error && <p className="text-[#ff003c] text-sm animate-fade-in bg-[#ff003c]/10 px-4 py-2 rounded border border-[#ff003c]/20 font-mono">ERROR: {error}</p>}
        </div>
      </div>

      {/* Script Terminal */}
      {segments.length > 0 && (
        <div className="flex-1 min-h-0 bg-[#0a0a0c] border border-zinc-800 rounded-lg shadow-md flex flex-col overflow-hidden animate-fade-in-up" style={{ animationDelay: '0.2s' }}>
          <div className="p-3 border-b border-zinc-800 bg-[#0f1012] flex items-center justify-between sticky top-0 z-10 shadow-lg">
            <div className="flex items-center gap-2">
              <Activity size={16} className="text-[#00f3ff]" />
              <h3 className="text-xs font-bold text-zinc-400 uppercase tracking-widest font-mono">Communication_Stream</h3>
            </div>
            <div className="flex items-center gap-3">
                <button 
                  onClick={downloadScript}
                  className="text-zinc-500 hover:text-white p-1 hover:bg-zinc-800 rounded transition-colors"
                  title="Export Log"
                >
                    <FileDown size={16} />
                </button>
            </div>
          </div>

          <div 
            ref={scriptContainerRef}
            className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth custom-scrollbar font-mono text-sm bg-black/40"
          >
            {segments.map((seg, idx) => {
              const isActive = idx === activeIndex;
              const isHost1 = seg.speaker.includes(cleanText(hosts.host1));

              return (
                <div 
                  key={idx} 
                  ref={el => { segmentRefs.current[idx] = el; }}
                  className={`flex w-full ${isHost1 ? 'justify-start' : 'justify-end'} animate-fade-in`}
                >
                    <div 
                        data-source="Neural_Podcast" 
                        className={`
                       max-w-[85%] rounded-lg p-4 relative transition-all duration-300
                       ${isActive 
                           ? isHost1 
                                ? 'bg-cyan-950/30 border border-cyan-500/50 shadow-[0_0_15px_rgba(6,182,212,0.1)]' 
                                : 'bg-rose-950/30 border border-[#ff003c]/50 shadow-[0_0_15px_rgba(255,0,60,0.1)]'
                           : 'bg-zinc-900/50 border border-zinc-800 hover:border-zinc-700'
                       }
                    `}>
                        {/* Speaker Label */}
                        <div className={`
                            absolute -top-3 px-2 py-0.5 rounded text-[9px] font-bold uppercase tracking-wider border shadow-sm flex items-center gap-1
                            ${isHost1 
                                ? 'left-4 bg-[#0a0a0c] text-cyan-400 border-cyan-900' 
                                : 'right-4 bg-[#0a0a0c] text-[#ff003c] border-rose-900 flex-row-reverse'
                            }
                        `}>
                             <Radio size={10} />
                             {seg.speaker}
                        </div>

                        <p className={`leading-relaxed text-[13px] ${isActive ? 'text-white' : 'text-zinc-400'}`}>
                           {seg.text}
                        </p>
                    </div>
                </div>
              );
            })}
             <div className="h-12"></div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lightbulb, Image as ImageIcon, Download, RefreshCw, Settings2, Hexagon, Globe, Archive } from 'lucide-react';
import { Concept, Chapter, FileContext } from '../types';
import { extractConcepts, generateConceptImage } from '../services/gemini';
import { Loader } from './ui/Loader';
import JSZip from 'jszip';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Digital Art', 'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Sketch', 
  'Cyberpunk', 'Vaporwave', 'Neon', 'Line Art', 'Low Poly', 'Isometric',
  '3D Render', 'Pixel Art'
];
const RATIOS = ['1:1', '16:9', '4:3', '9:16', '3:4', '2:3'];

export const Visualizer: React.FC<Props> = ({ chapter, fileContext }) => {
  const [concepts, setConcepts] = useState<Concept[]>([]);
  const [images, setImages] = useState<Record<string, string>>({});
  const [loadingImages, setLoadingImages] = useState<Record<string, boolean>>({});
  const [isInitializing, setIsInitializing] = useState(false);

  const [selectedStyle, setSelectedStyle] = useState('Cyberpunk');
  const [selectedRatio, setSelectedRatio] = useState('1:1');
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    let mounted = true;
    const loadConcepts = async () => {
      setIsInitializing(true);
      try {
        const extracted = await extractConcepts(fileContext, chapter);
        if (mounted) setConcepts(extracted);
      } catch (err) {
        console.error(err);
      } finally {
        if (mounted) setIsInitializing(false);
      }
    };

    loadConcepts();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  const handleGenerateImage = async (concept: Concept, forceRegenerate = false) => {
    if (loadingImages[concept.term] && !forceRegenerate) return;

    setLoadingImages(prev => ({ ...prev, [concept.term]: true }));
    try {
      const imgUrl = await generateConceptImage(concept.visualPrompt, selectedStyle, selectedRatio);
      setImages(prev => ({ ...prev, [concept.term]: imgUrl }));
    } catch (e) {
      console.error("Image gen failed", e);
    } finally {
      setLoadingImages(prev => ({ ...prev, [concept.term]: false }));
    }
  };

  const handleDownloadAll = async () => {
     const zip = new JSZip();
     let count = 0;

     // Iterate over generated images
     Object.entries(images).forEach(([term, dataUrl]) => {
         const base64Data = dataUrl.split(',')[1];
         zip.file(`lumina-concept-${term.replace(/\s+/g, '_')}.png`, base64Data, {base64: true});
         count++;
     });

     if (count === 0) return;

     const content = await zip.generateAsync({type: "blob"});
     const url = URL.createObjectURL(content);
     const a = document.createElement('a');
