                          {!isLoading && <span>AWAITING_NEURAL_STREAM</span>}
                      </div>
                  )}
               </div>

               {/* Controls Bar - Adjusted Flex Ratios */}
               <div className="bg-[#020202] p-4 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-4 text-[10px] font-mono text-zinc-600">
