];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('English');

  const handleGenerate = async () => {
    setError(null);
    setIsGenerating(true);
    setStatus("Authenticating & Generating...");

    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }

      const url = await generateSummaryVideo(fileContext, chapter, setStatus, selectedStyle, selectedLanguage);
      setVideoUrl(url);
    } catch (e: any) {
      console.error(e);
      let msg = "Generation failed.";
      if (e.message?.includes("Requested entity was not found")) {
        msg = "Key Invalid. Paid project key required.";
        await requestVeoKey();
      } else if (e.message) {
        msg = e.message;
      }
      setError(msg);
    } finally {
      setIsGenerating(false);
      setStatus("");
    }
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100">

      {/* Standard Toolbar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono">
                 <MonitorPlay size={18} className="text-[#00f3ff]" />
                 <span>Neural_Cinema</span>
              </div>
          </div>

          <div className="flex items-center gap-4">
              {/* Settings */}
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500">
                     <Settings2 size={16} />
                 </div>
                 <select 
                    value={selectedStyle}
                    onChange={(e) => setSelectedStyle(e.target.value)}
                    className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-28 bg-[#050505]"
                 >
                    {STYLES.map(t => <option key={t} value={t}>{t}</option>)}
                 </select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500">
                     <Globe size={16} />
                 </div>
                 <select
                    value={selectedLanguage}
                    onChange={(e) => setSelectedLanguage(e.target.value)}
                    className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]"
                 >
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
          </div>
       </div>

      <div className="flex-1 bg-[#050505] rounded-lg border border-zinc-800 relative overflow-hidden shadow-inner flex flex-col items-center justify-center p-6">
          {/* Background Grid */}
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#1f2937_1px,transparent_1px),linear-gradient(to_bottom,#1f2937_1px,transparent_1px)] bg-[size:40px_40px] opacity-[0.05] pointer-events-none"></div>

          {!videoUrl && !isGenerating && (
            <div className="z-10 text-center max-w-md space-y-8 animate-fade-in-up">
              <div className="w-24 h-24 bg-black rounded-full flex items-center justify-center mx-auto border border-zinc-800 shadow-[0_0_30px_rgba(0,243,255,0.1)] relative group">
                <div className="absolute inset-0 rounded-full border border-dashed border-zinc-700 animate-spin-slow"></div>
                <Film className="text-[#00f3ff] w-10 h-10 group-hover:scale-110 transition-transform" />
              </div>

              <div className="space-y-2">
                 <p className="text-zinc-500 font-mono text-xs">
                  Synthesize visual summary for "{chapter.title}" using VEO-3.1 model.
                </p>
              </div>

              <div className="bg-amber-900/10 border border-amber-900/30 p-3 rounded-sm text-amber-500/80 text-xs text-left flex gap-3 font-mono justify-center items-center">
                <AlertCircle size={14} className="shrink-0" />
                <p>PAID_KEY_REQUIRED</p>
              </div>

              <button
                onClick={handleGenerate}
                className="w-full py-4 bg-white text-black font-bold rounded-sm hover:bg-[#00f3ff] transition-all flex items-center justify-center gap-3 hover:scale-[1.02] shadow-lg font-mono uppercase tracking-widest"
              >
                <Video size={18} />
                Generate_Sequence
              </button>

              {error && <p className="text-[#ff003c] text-xs mt-2 animate-fade-in font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">ERROR: {error}</p>}
            </div>
          )}

          {isGenerating && (
             <div className="z-10 text-center w-full max-w-md">
                <Loader text={status} />
                <div className="w-full h-1 bg-zinc-900 rounded-full mt-8 overflow-hidden">
                    <div className="h-full bg-[#00f3ff] animate-pulse-slow w-full origin-left scale-x-50 shadow-[0_0_10px_#00f3ff]"></div>
                </div>
             </div>
          )}

          {videoUrl && (
            <div className="z-10 w-full h-full flex flex-col items-center justify-center gap-6 animate-fade-in">
              <div className="relative rounded-sm shadow-[0_0_50px_rgba(0,0,0,0.8)] border border-zinc-700 bg-black overflow-hidden max-h-[60vh] w-full max-w-4xl aspect-video group">
                 <div className="absolute top-0 left-0 bg-[#ff003c] text-white text-[10px] font-bold px-2 py-0.5 z-20 font-mono">REC</div>
                 <video 
                  src={videoUrl} 
                  controls 
                  autoPlay 
                  loop 
                  className="w-full h-full object-contain"
                />
              </div>
              <div className="flex gap-4">
                 <a 
                   href={videoUrl} 
                   download={`lumina-summary-${chapter.id}.mp4`}
                   className="px-6 py-3 bg-[#00f3ff] hover:bg-[#00c2cc] text-black rounded-sm flex items-center gap-2 transition-all shadow-[0_0_20px_rgba(0,243,255,0.4)] hover:scale-105 font-bold uppercase tracking-wide font-mono text-sm"
                 >
                   <Download size={18} />
                   Save_File
                 </a>
                 <button
                   onClick={() => setVideoUrl(null)}
                   className="px-6 py-3 bg-zinc-900 hover:bg-zinc-800 text-zinc-400 rounded-sm flex items-center gap-2 transition-colors border border-zinc-700 font-mono text-sm uppercase"
                 >
                   <RotateCcw size={18} />
                   Reset
                 </button>
              </div>
            </div>
          )}
      </div>
    </div>
  );
};
